    style.textContent = [
      '.' + COPY_MARKDOWN_BUTTON_CLASS + ' {',
      '  border: 1px solid rgba(60, 64, 67, 0.16);',
      '  background: transparent;',
      '  border-radius: 999px;',
      '  padding: 0.35rem 0.7rem;',
      '  font: inherit;',
      '  cursor: pointer;',
      '}',
      '.' + COPY_MARKDOWN_BUTTON_CLASS + ':hover {',
      '  background: rgba(60, 64, 67, 0.08);',
      '}'
    ].join('\n');
